import type { HomeScreen } from './home-screen/home-screen.component.js';
import type { RouteConfig } from '../../router.js';

export function homeRoutes(): Record<string, RouteConfig> {
    return {
        '/': {
            render: async () => {
                await import('./home-screen/home-screen.component.js');
                const screen = document.createElement('home-screen') as HomeScreen;
                screen.className = 'home-screen';
                // Let the screen own its data load — never block the route render.
                void screen.loadSummaries();
                return screen;
            },
        },
    };
}
