import { navigate, startRouter } from './router.js';
import { registerServiceWorker } from './services/service-worker.service.js';
import { attachNotificationClickBridge } from './services/notification-click-bridge.js';
import { notificationsService } from './services/notifications.service.js';
import { homeRoutes } from './components/home/home.routes.js';
import { goalRoutes } from './components/goal/goal.routes.js';
import { agendaRoutes } from './components/agenda/agenda.routes.js';
import { healthRoutes } from './components/health/health.routes.js';
import { socialRoutes } from './components/social/social.routes.js';
import { vietnameseRoutes } from './components/vietnamese/vietnamese.routes.js';
import { projectsRoutes } from './components/projects/projects.routes.js';
import { extraRoutes } from './components/extra/extra.routes.js';
import { statusScreenRoutes } from './components/status-screen/status-screen.routes.js';

import { handleStravaOAuthCallback } from './services/strava-callback.js';
import { DbService } from './db/db.service.js';
import { downloadAndLoadSnapshot } from './db/db-snapshot.service.js';
import { OfflineApiRouter } from './services/offline/offline-api-router.js';

let offlineApiRouter: OfflineApiRouter | null = null;



async function initializeLocalDatabase(): Promise<void> {
    console.log('[SYNC-DEBUG][app] initializeLocalDatabase() START');
    try {
        if (!offlineApiRouter) {
            offlineApiRouter = new OfflineApiRouter();
            offlineApiRouter.start();
            console.log('[SYNC-DEBUG][app] OfflineApiRouter started');
        }

        const dbService = DbService.getInstance();
        console.log('[SYNC-DEBUG][app] Calling dbService.init()...');
        await dbService.init();
        console.log('[SYNC-DEBUG][app] dbService.init() DONE');

        console.log('[SYNC-DEBUG][app] Calling dbService.exists()...');
        const exists = await dbService.exists();
        console.log('[SYNC-DEBUG][app] dbService.exists() =', exists);
        if (!exists) {
            console.log('[SYNC-DEBUG][app] DB does not exist, attempting snapshot download...');
            const loadedFromSnapshot = await downloadAndLoadSnapshot({ dbService });
            console.log('[SYNC-DEBUG][app] Snapshot download result:', loadedFromSnapshot);
            if (!loadedFromSnapshot) {
                console.log('[SYNC-DEBUG][app] Snapshot failed, calling initSchema()...');
                await dbService.initSchema();
                console.log('[SYNC-DEBUG][app] initSchema() DONE');
            }
        } else {
            console.log('[SYNC-DEBUG][app] DB already exists, skipping snapshot/schema init');
        }
        console.log('[SYNC-DEBUG][app] initializeLocalDatabase() COMPLETE');
    } catch (error) {
        console.warn('[SYNC-DEBUG][app] initializeLocalDatabase() FAILED:', error);
        console.warn('Local database initialization failed. Continuing in online-first mode.', error);
    }
}

export function startApp(): void {
    // ALWAYS attempt to register the service worker (it will return early in DEV mode).
    // This is required for offline caching to work in production!
    const swPromise = registerServiceWorker().catch(err => {
        console.error('Service Worker registration failed:', err);
    });

    if (!window.crossOriginIsolated) {
        console.warn('Environment is not Cross-Origin Isolated. Halting boot until Service Worker injects headers and reloads.');
        document.body.textContent = 'Initializing Offline Storage... Please wait.';

        swPromise.then(registration => {
            if (!registration) return; // e.g. in DEV mode

            if (registration.active) {
                window.location.reload();
            } else {
                registration.addEventListener('updatefound', () => {
                    const newWorker = registration.installing;
                    newWorker?.addEventListener('statechange', () => {
                        if (newWorker.state === 'activated') {
                            window.location.reload();
                        }
                    });
                });
            }
        });
        return; // Halt normal boot until reload
    }

    console.log('Motivation PWA Started (Isolated Mode)');

    handleStravaOAuthCallback();

    attachNotificationClickBridge({
        serviceWorkerContainer: navigator.serviceWorker,
        navigate,
        visibilityTarget: document,
        notifications: notificationsService,
    });

    void initializeLocalDatabase().then(() => {
        startRouter({
            ...homeRoutes(),
            ...goalRoutes(),
            ...agendaRoutes(),
            ...healthRoutes(),
            ...socialRoutes(),
            ...vietnameseRoutes(),
            ...projectsRoutes(),
            ...extraRoutes(),
            ...statusScreenRoutes(),
        }, document.getElementById('route-outlet')!);
    });

    // After the home screen is shown, pre-load section entry points during
    // browser idle time so the first navigation to each section is instant.
    requestIdleCallback(() => {
        void import('./components/health/health-dashboard-screen.component.js');
        void import('./components/projects/projects-dashboard-screen.component.js');
        void import('./components/vietnamese/vietnamese-dashboard-screen.component.js');
        void import('./components/goal/goals-screen.component.js');
        void import('./components/agenda/agenda-screen.component.js');
    });

    void registerPeriodicSync();
}

async function registerPeriodicSync(): Promise<void> {
    if (!('serviceWorker' in navigator)) return;
    try {
        const registration = await navigator.serviceWorker.ready;
        const periodicSync = registration.periodicSync;
        if (!periodicSync) return;
        await periodicSync.register('notifications-check', { minInterval: 60 * 60 * 1000 });
    } catch (err) {
        console.warn('Periodic sync registration failed', err);
    }
}
