import type { DbDriver } from '../types/db.js';
import type { Goal, NewGoal } from '../types/goals.js';
import { queryOne } from './query-one.js';
import { uuidv7 } from '../utils/uuid.js';

export function createGoalRepository(driver: DbDriver) {
    const repo = {
        async getAll(): Promise<Goal[]> {
            const allGoals = await driver.query<Goal>('SELECT * FROM goals');
            const goalMap = new Map<string, Goal>();
            for (const g of allGoals) {
                g.sub_goals = [];
                goalMap.set(g.id, g);
            }
            const roots: Goal[] = [];
            for (const g of allGoals) {
                if (g.parent_id) {
                    const parent = goalMap.get(g.parent_id);
                    if (parent) {
                        parent.sub_goals!.push(g);
                    } else {
                        roots.push(g);
                    }
                } else {
                    roots.push(g);
                }
            }
            return roots;
        },

        async findById(id: string): Promise<Goal | null> {
            const goal = await queryOne<Goal>(driver, 'SELECT * FROM goals WHERE id = ?', id);
            if (!goal) return null;
            const subGoals = await driver.query<Goal>('SELECT * FROM goals WHERE parent_id = ?', id);
            goal.sub_goals = subGoals;
            return goal;
        },

        async create(input: NewGoal): Promise<Goal> {
            const id = uuidv7();
            await driver.execute(
                'INSERT INTO goals (id, title, description, parent_id, status) VALUES (?, ?, ?, ?, ?)',
                id,
                input.title,
                input.description ?? null,
                input.parent_id ?? null,
                input.status ?? 'ACTIVE',
            );
            const created = await repo.findById(id);
            if (!created) {
                throw new Error(`Failed to load created goal: ${id}`);
            }
            return created;
        },

        async update(
            id: string,
            updates: Partial<Pick<Goal, 'title' | 'description' | 'status'>>,
        ): Promise<Goal | null> {
            const current = await repo.findById(id);
            if (!current) return null;

            const fields: string[] = [];
            const values: unknown[] = [];

            if (updates.title !== undefined && updates.title !== current.title) {
                fields.push('title = ?');
                values.push(updates.title);
            }
            if ('description' in updates && updates.description !== current.description) {
                fields.push('description = ?');
                values.push(updates.description ?? null);
            }
            if (updates.status !== undefined && updates.status !== current.status) {
                fields.push('status = ?');
                values.push(updates.status);
            }

            if (fields.length === 0) return current;

            fields.push("updated_at = datetime('now')");
            values.push(id);
            await driver.execute(`UPDATE goals SET ${fields.join(', ')} WHERE id = ?`, ...values);
            return repo.findById(id);
        },

        async delete(id: string): Promise<boolean> {
            const result = await driver.execute('DELETE FROM goals WHERE id = ?', id);
            return result.changes > 0;
        },
    };
    return repo;
}

export type GoalRepository = ReturnType<typeof createGoalRepository>;
