import {
    createGoalRepository,
    createHealthRepository,
    createSocialRepository,
    createVietnameseRepository,
    GOAL_ROUTE_KEYS,
    HEALTH_ROUTE_KEYS,
    SOCIAL_ROUTE_KEYS,
    VIETNAMESE_ROUTE_KEYS,
    type GoalRouteKey,
    type HealthRouteKey,
    type SocialRouteKey,
    type VietnameseRouteKey,
    type ApiResponse,
    type RouteContext,
} from '@motivation/shared';
import { Temporal } from '@js-temporal/polyfill';
import { DbService } from '../../db/db.service.js';
import {
    GoalOfflineRoutes,
    HealthOfflineRoutes,
    SocialOfflineRoutes,
    VietnameseOfflineRoutes,
} from './offline-routes.js';

interface OfflineRequestEnvelope {
    type: 'offline-request';
    request: {
        method: string;
        url: string;
        body?: string | null;
    };
}

export interface OfflineApiRouterOptions {
    onUnhandledRequest?: (request: RouteContext & { method: string; path: string }) => ApiResponse;
}

export class OfflineApiRouter {
    private readonly handleMessageBound = this.handleMessage.bind(this);
    private offlineRoutes: HealthOfflineRoutes | null = null;
    private goalOfflineRoutes: GoalOfflineRoutes | null = null;
    private socialOfflineRoutes: SocialOfflineRoutes | null = null;
    private vietnameseOfflineRoutes: VietnameseOfflineRoutes | null = null;

    constructor(private readonly options: OfflineApiRouterOptions = {}) {}

    start(): void {
        navigator.serviceWorker.addEventListener('message', this.handleMessageBound as unknown as EventListener);
    }

    stop(): void {
        navigator.serviceWorker.removeEventListener('message', this.handleMessageBound as unknown as EventListener);
    }

    private async handleMessage(event: MessageEvent<Partial<OfflineRequestEnvelope>>): Promise<void> {
        // If it's not an offline-request, it's not for us, so ignore it silently.
        if (event.data?.type !== 'offline-request') {
            return;
        }

        // If it is an offline-request, it MUST have a reply port to send the response back.
        if (!event.ports?.[0]) {
            console.warn('Ignoring malformed offline router message', {
                hasData: true,
                dataType: event.data.type,
                hasPort: false,
            });
            return;
        }

        const envelope = event.data as OfflineRequestEnvelope;
        const port = event.ports[0];
        try {
            const request = this.toRouteContext(envelope.request);
            const response = await this.route(request);
            port.postMessage(response);
        } catch (error) {
            port.postMessage({
                status: 503,
                headers: { 'Content-Type': 'application/json' },
                body: {
                    error: error instanceof Error ? error.message : 'Offline router failed',
                },
            } satisfies ApiResponse);
        }
    }

    private toRouteContext(request: OfflineRequestEnvelope['request']): RouteContext & { method: string; path: string } {
        const parsedUrl = new URL(request.url, window.location.origin);
        let body: unknown = undefined;

        if (typeof request.body === 'string' && request.body.trim().length > 0) {
            body = JSON.parse(request.body);
        }

        return {
            method: request.method,
            path: parsedUrl.pathname,
            params: {},
            query: parsedUrl.searchParams,
            body,
        };
    }

    private async route(request: RouteContext & { method: string; path: string }): Promise<ApiResponse> {
        const goalResponse = await this.routeGoals(request);
        if (goalResponse) {
            return goalResponse;
        }

        const healthResponse = await this.routeHealth(request);
        if (healthResponse) {
            return healthResponse;
        }

        const socialResponse = await this.routeSocial(request);
        if (socialResponse) {
            return socialResponse;
        }

        const vietnameseResponse = await this.routeVietnamese(request);
        if (vietnameseResponse) {
            return vietnameseResponse;
        }

        if (this.options.onUnhandledRequest) {
            return this.options.onUnhandledRequest(request);
        }

        return {
            status: 404,
            headers: { 'Content-Type': 'application/json' },
            body: { error: `Offline route not found: ${request.method} ${request.path}` },
        };
    }

    private async routeGoals(request: RouteContext & { method: string; path: string }): Promise<ApiResponse | null> {
        const relativePath = this.toSectionPath(request.path, '/api/goals');
        if (!relativePath) {
            return null;
        }

        for (const key of GOAL_ROUTE_KEYS) {
            const match = this.matchRoute(key, request.method, relativePath);
            if (!match) {
                continue;
            }

            const routes = this.getGoalOfflineRoutes();
            return routes[key]({
                params: match.params,
                query: request.query,
                body: request.body,
            });
        }

        return null;
    }

    private async routeHealth(request: RouteContext & { method: string; path: string }): Promise<ApiResponse | null> {
        const relativePath = this.toSectionPath(request.path, '/api/sections/health');
        if (!relativePath) {
            return null;
        }

        for (const key of HEALTH_ROUTE_KEYS) {
            const match = this.matchRoute(key, request.method, relativePath);
            if (!match) {
                continue;
            }

            const routes = this.getOfflineRoutes();
            return await routes[key]({
                params: match.params,
                query: request.query,
                body: request.body,
            });
        }

        return null;
    }

    private async routeSocial(request: RouteContext & { method: string; path: string }): Promise<ApiResponse | null> {
        const relativePath = this.toSectionPath(request.path, '/api/sections/social');
        if (!relativePath) {
            return null;
        }

        for (const key of SOCIAL_ROUTE_KEYS) {
            const match = this.matchRoute(key, request.method, relativePath);
            if (!match) {
                continue;
            }

            const routes = this.getSocialOfflineRoutes();
            return routes[key]({
                params: match.params,
                query: request.query,
                body: request.body,
            });
        }

        return null;
    }

    private async routeVietnamese(request: RouteContext & { method: string; path: string }): Promise<ApiResponse | null> {
        const relativePath = this.toSectionPath(request.path, '/api/sections/vietnamese');
        if (!relativePath) {
            return null;
        }

        for (const key of VIETNAMESE_ROUTE_KEYS) {
            const match = this.matchRoute(key, request.method, relativePath);
            if (!match) {
                continue;
            }

            const routes = this.getVietnameseOfflineRoutes();
            return routes[key]({
                params: match.params,
                query: request.query,
                body: request.body,
            });
        }

        return null;
    }

    private getGoalOfflineRoutes(): GoalOfflineRoutes {
        if (this.goalOfflineRoutes) {
            return this.goalOfflineRoutes;
        }

        this.goalOfflineRoutes = new GoalOfflineRoutes(
            createGoalRepository(DbService.getInstance().driver),
        );
        return this.goalOfflineRoutes;
    }

    private getOfflineRoutes(): HealthOfflineRoutes {
        if (this.offlineRoutes) {
            return this.offlineRoutes;
        }

        const today = Temporal.Now.plainDateISO();
        this.offlineRoutes = new HealthOfflineRoutes(
            createHealthRepository(DbService.getInstance().driver),
            {
                defaultActivitiesRange: {
                    fromDate: today.subtract({ days: 30 }).toString(),
                    toDate: today.add({ days: 30 }).toString(),
                },
            },
        );
        return this.offlineRoutes;
    }

    private getSocialOfflineRoutes(): SocialOfflineRoutes {
        if (this.socialOfflineRoutes) {
            return this.socialOfflineRoutes;
        }

        this.socialOfflineRoutes = new SocialOfflineRoutes(
            createSocialRepository(DbService.getInstance().driver),
        );
        return this.socialOfflineRoutes;
    }

    private getVietnameseOfflineRoutes(): VietnameseOfflineRoutes {
        if (this.vietnameseOfflineRoutes) {
            return this.vietnameseOfflineRoutes;
        }

        this.vietnameseOfflineRoutes = new VietnameseOfflineRoutes(
            createVietnameseRepository(DbService.getInstance().driver),
        );
        return this.vietnameseOfflineRoutes;
    }

    private matchRoute(
        key: HealthRouteKey | GoalRouteKey | SocialRouteKey | VietnameseRouteKey,
        requestMethod: string,
        requestPath: string,
    ): { params: Record<string, string> } | null {
        const [method, templatePath] = key.split(' ') as [string, string];
        if (method !== requestMethod.toUpperCase()) {
            return null;
        }

        const templateParts = templatePath.split('/').filter(Boolean);
        const requestParts = requestPath.split('/').filter(Boolean);
        if (templateParts.length !== requestParts.length) {
            return null;
        }

        const params: Record<string, string> = {};
        for (let i = 0; i < templateParts.length; i += 1) {
            const templatePart = templateParts[i];
            const requestPart = requestParts[i];
            if (templatePart.startsWith(':')) {
                params[templatePart.slice(1)] = requestPart;
                continue;
            }
            if (templatePart !== requestPart) {
                return null;
            }
        }

        return { params };
    }

    private toSectionPath(path: string, prefix: string): string | null {
        if (!path.startsWith(prefix)) {
            return null;
        }

        const relative = path.slice(prefix.length);
        return relative.length > 0 ? relative : '/';
    }
}
