import { Temporal } from '@js-temporal/polyfill';
import { RATINGS, REVIEW_STATES, type Rating } from '../types/vietnamese.js';
import type { NewCard, NewDeck, NewReview } from '../types/vietnamese.js';
import type { VietnameseRepository } from '../repositories/vietnamese.repository.js';
import type { ApiResponse, RouteContext } from './health-routes.js';
import { AbstractRouteResponses } from './response-helpers.js';
import {
    parseOptionalSanitizedText,
    parsePositiveInteger,
    parseRequiredSanitizedText,
    sanitizeText,
} from './validation-utils.js';

export type VietnameseRouteKey =
    | 'GET /decks'
    | 'GET /decks/stats'
    | 'GET /decks/:id'
    | 'POST /decks'
    | 'PATCH /decks/:id'
    | 'DELETE /decks/:id'
    | 'GET /cards'
    | 'GET /cards/:id'
    | 'PATCH /cards/:id'
    | 'DELETE /cards/:id'
    | 'GET /decks/:id/cards'
    | 'POST /decks/:id/cards'
    | 'GET /decks/:id/due'
    | 'GET /cards/:id/reviews'
    | 'POST /cards/:id/reviews'
    | 'GET /review'
    | 'POST /review';

export const VIETNAMESE_ROUTE_KEYS: readonly VietnameseRouteKey[] = [
    'GET /decks',
    'GET /decks/stats',
    'GET /decks/:id',
    'POST /decks',
    'PATCH /decks/:id',
    'DELETE /decks/:id',
    'GET /cards',
    'GET /cards/:id',
    'PATCH /cards/:id',
    'DELETE /cards/:id',
    'GET /decks/:id/cards',
    'POST /decks/:id/cards',
    'GET /decks/:id/due',
    'GET /cards/:id/reviews',
    'POST /cards/:id/reviews',
    'GET /review',
    'POST /review',
] as const;

export interface FsrsService {
    reviewCard(current: unknown, rating: Rating, nowString?: string): Omit<NewReview, 'card_id'>;
}

export interface IVietnameseRoutes {
    'GET /decks'(ctx: RouteContext): Promise<ApiResponse>;
    'GET /decks/stats'(ctx: RouteContext): Promise<ApiResponse>;
    'GET /decks/:id'(ctx: RouteContext): Promise<ApiResponse>;
    'POST /decks'(ctx: RouteContext): Promise<ApiResponse>;
    'PATCH /decks/:id'(ctx: RouteContext): Promise<ApiResponse>;
    'DELETE /decks/:id'(ctx: RouteContext): Promise<ApiResponse>;
    'GET /cards'(ctx: RouteContext): Promise<ApiResponse>;
    'GET /cards/:id'(ctx: RouteContext): Promise<ApiResponse>;
    'PATCH /cards/:id'(ctx: RouteContext): Promise<ApiResponse>;
    'DELETE /cards/:id'(ctx: RouteContext): Promise<ApiResponse>;
    'GET /decks/:id/cards'(ctx: RouteContext): Promise<ApiResponse>;
    'POST /decks/:id/cards'(ctx: RouteContext): Promise<ApiResponse>;
    'GET /decks/:id/due'(ctx: RouteContext): Promise<ApiResponse>;
    'GET /cards/:id/reviews'(ctx: RouteContext): Promise<ApiResponse>;
    'POST /cards/:id/reviews'(ctx: RouteContext): Promise<ApiResponse>;
    'GET /review'(ctx: RouteContext): Promise<ApiResponse>;
    'POST /review'(ctx: RouteContext): Promise<ApiResponse>;
}

export interface VietnameseRouteOptions {
    fsrsService: FsrsService;
}

export abstract class AbstractVietnameseRoutes extends AbstractRouteResponses implements IVietnameseRoutes {
    protected abstract readonly repo: VietnameseRepository;
    protected readonly options: VietnameseRouteOptions;

    constructor(options: VietnameseRouteOptions) {
        super();
        this.options = options;
    }

    protected sanitizeText(value: string): string {
        return sanitizeText(value);
    }

    protected parseRequiredText(value: unknown): string | null {
        return parseRequiredSanitizedText(value);
    }

    protected parseOptionalText(value: unknown): { valid: boolean; value?: string } {
        return parseOptionalSanitizedText(value);
    }

    protected parseLimit(query: URLSearchParams, fallback: number): number {
        return parsePositiveInteger(query.get('limit'), fallback);
    }

    protected validateReviewState(value: unknown): NewReview['state'] {
        if (typeof value === 'string' && REVIEW_STATES.includes(value as NewReview['state'])) {
            return value as NewReview['state'];
        }

        throw new Error(`state must be one of: ${REVIEW_STATES.join(', ')}`);
    }

    protected validateOptionalReviewRating(value: unknown): NewReview['rating'] {
        if (value === undefined) {
            return undefined;
        }

        if (Number.isInteger(value) && RATINGS.includes(value as Rating)) {
            return value as NewReview['rating'];
        }

        throw new Error(`rating must be one of: ${RATINGS.join(', ')}`);
    }

    protected validateRequiredReviewRating(value: unknown): Rating {
        if (Number.isInteger(value) && RATINGS.includes(value as Rating)) {
            return value as Rating;
        }

        throw new Error('Valid card_id and rating (1-4) are required');
    }

    protected validateCardId(value: unknown): string {
        if (typeof value === 'string' && value.trim().length > 0) {
            return value;
        }

        throw new Error('Valid card_id and rating (1-4) are required');
    }

    abstract 'GET /decks'(ctx: RouteContext): Promise<ApiResponse>;
    abstract 'GET /decks/stats'(ctx: RouteContext): Promise<ApiResponse>;
    abstract 'GET /decks/:id'(ctx: RouteContext): Promise<ApiResponse>;
    abstract 'POST /decks'(ctx: RouteContext): Promise<ApiResponse>;
    abstract 'PATCH /decks/:id'(ctx: RouteContext): Promise<ApiResponse>;
    abstract 'DELETE /decks/:id'(ctx: RouteContext): Promise<ApiResponse>;
    abstract 'GET /cards'(ctx: RouteContext): Promise<ApiResponse>;
    abstract 'GET /cards/:id'(ctx: RouteContext): Promise<ApiResponse>;
    abstract 'PATCH /cards/:id'(ctx: RouteContext): Promise<ApiResponse>;
    abstract 'DELETE /cards/:id'(ctx: RouteContext): Promise<ApiResponse>;
    abstract 'GET /decks/:id/cards'(ctx: RouteContext): Promise<ApiResponse>;
    abstract 'POST /decks/:id/cards'(ctx: RouteContext): Promise<ApiResponse>;
    abstract 'GET /decks/:id/due'(ctx: RouteContext): Promise<ApiResponse>;
    abstract 'GET /cards/:id/reviews'(ctx: RouteContext): Promise<ApiResponse>;
    abstract 'POST /cards/:id/reviews'(ctx: RouteContext): Promise<ApiResponse>;
    abstract 'GET /review'(ctx: RouteContext): Promise<ApiResponse>;
    abstract 'POST /review'(ctx: RouteContext): Promise<ApiResponse>;
}

export class VietnameseServerRoutes extends AbstractVietnameseRoutes {
    protected readonly repo: VietnameseRepository;

    constructor(repo: VietnameseRepository, options: VietnameseRouteOptions) {
        super(options);
        this.repo = repo;
    }

    async 'GET /decks'(): Promise<ApiResponse> {
        return this.ok(await this.repo.getAllDecks());
    }

    async 'GET /decks/stats'(): Promise<ApiResponse> {
        return this.ok(await this.repo.getDeckStats());
    }

    async 'GET /decks/:id'({ params }: RouteContext): Promise<ApiResponse> {
        const deck = await this.repo.getDeckById(params.id);
        if (!deck) return this.notFound('Deck not found');
        return this.ok(deck);
    }

    async 'POST /decks'({ body }: RouteContext): Promise<ApiResponse> {
        const b = (body ?? {}) as Record<string, unknown>;
        const name = this.parseRequiredText(b.name);
        const description = this.parseOptionalText(b.description);

        if (!name) return this.badRequest('Name is required');
        if (!description.valid) return this.badRequest('Description must be a string when provided');

        const deck = await this.repo.createDeck({ name, description: description.value } as NewDeck);
        return this.created(deck);
    }

    async 'PATCH /decks/:id'({ params, body }: RouteContext): Promise<ApiResponse> {
        const b = (body ?? {}) as Record<string, unknown>;
        const updates: { name?: string; description?: string } = {};

        if ('name' in b) {
            const name = this.parseRequiredText(b.name);
            if (!name) return this.badRequest('Name is required');
            updates.name = name;
        }

        if ('description' in b) {
            const description = this.parseOptionalText(b.description);
            if (!description.valid) return this.badRequest('Description must be a string when provided');
            updates.description = description.value;
        }

        const updated = await this.repo.updateDeck(params.id, updates);
        if (!updated) return this.notFound('Deck not found');
        return this.ok(updated);
    }

    async 'DELETE /decks/:id'({ params }: RouteContext): Promise<ApiResponse> {
        const deleted = await this.repo.deleteDeck(params.id);
        if (!deleted) return this.notFound('Deck not found');
        return this.noContent();
    }

    async 'GET /cards'(): Promise<ApiResponse> {
        return this.ok(await this.repo.getAllCards());
    }

    async 'GET /cards/:id'({ params }: RouteContext): Promise<ApiResponse> {
        const card = await this.repo.getCardById(params.id);
        if (!card) return this.notFound('Card not found');
        return this.ok(card);
    }

    async 'PATCH /cards/:id'({ params, body }: RouteContext): Promise<ApiResponse> {
        const b = (body ?? {}) as Record<string, unknown>;
        const updates: { front?: string; back?: string; notes?: string } = {};

        if ('front' in b) {
            const front = this.parseRequiredText(b.front);
            if (!front) return this.badRequest('Front is required');
            updates.front = front;
        }

        if ('back' in b) {
            const back = this.parseRequiredText(b.back);
            if (!back) return this.badRequest('Back is required');
            updates.back = back;
        }

        if ('notes' in b) {
            const notes = this.parseOptionalText(b.notes);
            if (!notes.valid) return this.badRequest('Notes must be a string when provided');
            updates.notes = notes.value;
        }

        const updated = await this.repo.updateCard(params.id, updates);
        if (!updated) return this.notFound('Card not found');
        return this.ok(updated);
    }

    async 'DELETE /cards/:id'({ params }: RouteContext): Promise<ApiResponse> {
        const existing = await this.repo.getCardById(params.id);
        if (!existing) return this.notFound('Card not found');
        await this.repo.deleteCard(params.id);
        return this.noContent();
    }

    async 'GET /decks/:id/cards'({ params }: RouteContext): Promise<ApiResponse> {
        return this.ok(await this.repo.getCardsByDeckId(params.id));
    }

    async 'POST /decks/:id/cards'({ params, body }: RouteContext): Promise<ApiResponse> {
        const b = (body ?? {}) as Record<string, unknown>;
        const front = this.parseRequiredText(b.front);
        const back = this.parseRequiredText(b.back);
        const notes = this.parseOptionalText(b.notes);

        if (!front || !back) return this.badRequest('Front and back are required');
        if (!notes.valid) return this.badRequest('Notes must be a string when provided');

        const card = await this.repo.createCard({
            deck_id: params.id,
            front,
            back,
            notes: notes.value,
        } as NewCard);
        return this.created(card);
    }

    async 'GET /decks/:id/due'({ params }: RouteContext): Promise<ApiResponse> {
        return this.ok(await this.repo.getDueCards(params.id));
    }

    async 'GET /cards/:id/reviews'({ params }: RouteContext): Promise<ApiResponse> {
        return this.ok(await this.repo.getReviewsByCardId(params.id));
    }

    async 'POST /cards/:id/reviews'({ params, body }: RouteContext): Promise<ApiResponse> {
        const b = (body ?? {}) as Record<string, unknown>;
        let state: NewReview['state'];
        let rating: NewReview['rating'];

        try {
            state = this.validateReviewState(b.state);
            rating = this.validateOptionalReviewRating(b.rating);
        } catch (error) {
            return this.badRequest(error instanceof Error ? error.message : 'Invalid review payload');
        }

        const review = await this.repo.createReview({
            card_id: params.id,
            state,
            stability: Number(b.stability ?? 0),
            difficulty: Number(b.difficulty ?? 0),
            scheduled_days: Number(b.scheduled_days ?? 0),
            elapsed_days: Number(b.elapsed_days ?? 0),
            rating,
            due: String(b.due ?? Temporal.Now.instant().toString()),
            last_review: b.last_review === undefined ? undefined : String(b.last_review),
        });
        return this.created(review);
    }

    async 'GET /review'({ query }: RouteContext): Promise<ApiResponse> {
        const limit = this.parseLimit(query, 10);
        return this.ok(await this.repo.getDueCardsFromAllDecks(limit));
    }

    async 'POST /review'({ body }: RouteContext): Promise<ApiResponse> {
        const b = (body ?? {}) as Record<string, unknown>;
        let cardId: string;
        let rating: Rating;

        try {
            cardId = this.validateCardId(b.card_id);
            rating = this.validateRequiredReviewRating(b.rating);
        } catch (error) {
            return this.badRequest(error instanceof Error ? error.message : 'Invalid review payload');
        }

        const card = await this.repo.getCardById(cardId);
        if (!card) return this.notFound('Card not found');

        const latestReview = await this.repo.getLatestReviewByCardId(cardId);
        const result = this.options.fsrsService.reviewCard(latestReview, rating);

        const newReview = await this.repo.createReview({
            card_id: cardId,
            state: result.state,
            stability: result.stability,
            difficulty: result.difficulty,
            scheduled_days: result.scheduled_days,
            elapsed_days: result.elapsed_days,
            rating: result.rating,
            due: result.due,
            last_review: result.last_review ?? undefined,
        });

        return this.created(newReview);
    }
}
