import {
    GoalServerRoutes,
    SocialServerRoutes,
    VietnameseServerRoutes,
    AbstractHealthRoutes,
    type GoalRepository,
    type SocialRepository,
    type VietnameseRepository,
    type ApiResponse,
    type HealthRepository,
    type HealthRouteOptions,
} from '@motivation/shared';

export class HealthOfflineRoutes extends AbstractHealthRoutes {
    protected readonly repo: HealthRepository;

    constructor(repo: HealthRepository, options: HealthRouteOptions) {
        super(options);
        this.repo = repo;
    }
}

export class GoalOfflineRoutes extends GoalServerRoutes {
    constructor(repo: GoalRepository) {
        super(repo);
    }
}

export class SocialOfflineRoutes extends SocialServerRoutes {
    constructor(repo: SocialRepository) {
        super(repo);
    }
}

const unsupportedFsrsService = {
    reviewCard(): never {
        throw new Error('FSRS review is not available in offline mode');
    },
};

export class VietnameseOfflineRoutes extends VietnameseServerRoutes {
    constructor(repo: VietnameseRepository) {
        super(repo, { fsrsService: unsupportedFsrsService });
    }

    async 'POST /review'(): Promise<ApiResponse> {
        return this.unavailable('Vietnamese review scheduling requires server connection');
    }
}
